import androidx.test.ext.junit.runners.AndroidJUnit4
import org.hamcrest.CoreMatchers.equalTo
import org.hamcrest.MatcherAssert.assertThat
import org.json.JSONObject
import org.junit.Test
import org.junit.runner.RunWith

@RunWith(AndroidJUnit4::class)
class AnkiDroidJsAPIReproductionTest : RobolectricTest() {

    @Test
    fun ankiGetCardQueueTypeTest() = runTest {
        val models = col.notetypes
        val didA = addDeck("Test", setAsSelected = true)
        val basic = models.byName(AnkiDroidApp.appResources.getString(R.string.basic_model_name))
        basic!!.put("did", didA)
        addNoteUsingBasicModel("foo", "bar")

        val reviewer: Reviewer = ReviewerTest.startReviewer(this)
        val jsapi = reviewer.jsApi
        reviewer.displayCardAnswer()

        waitForAsyncTasksToComplete()

        val response = getDataFromRequest("cardQueue", jsapi)
        val jsonObject = JSONObject(response)
        val value = jsonObject.get("value")

        // The bug is that value is a String, but it should be an Integer
        assertThat(value is String, equalTo(true)) // Currently true (reproducing bug)
        // assertThat(value is Int, equalTo(true)) // Expected behavior
    }

    companion object {
        fun jsApiContract(data: String = ""): ByteArray {
            return JSONObject().apply {
                put("version", "0.0.2")
                put("developer", "test@example.com")
                put("data", data)
            }.toString().toByteArray()
        }

        suspend fun getDataFromRequest(
            methodName: String,
            jsAPI: AnkiDroidJsAPI,
            apiData: String = ""
        ): String {
            return jsAPI.handleJsApiRequest(methodName, jsApiContract(apiData), false)
                .decodeToString()
        }
    }
}
"}

